import * as React from "react";
import { Box, Input, Button, Link, Image } from "theme-ui";
import Tippy from "@tippyjs/react";
import ClipboardJS from "clipboard";
const Badge = ({ theme = "single", onClose, size = "xl", repo = "" } = {}) => {
  const imageSrc = "https://www.trackawesomelist.com/badge.svg";
  const imageHref = `https://www.trackawesomelist.com/${repo}`;
  const imageAlt = "Track Awesome List";
  const [badgeText, setBadgeText] = React.useState(
    `[![${imageAlt}](${imageSrc})](${imageHref})`
  );
  const [visible, setVisible] = React.useState(false);
  const show = () => setVisible(true);
  const hide = () => setVisible(false);
  React.useEffect(() => {
    const clipboard = new ClipboardJS("#copy-badge-text");
    clipboard.on("success", function (e) {
      show();
      setTimeout(() => {
        hide();
      }, 1500);
      e.clearSelection();
    });
  }, null);
  return (
    <Box sx={{ width: ["auto", size] }}>
      <Box pb="default">
        <Link href={imageHref}>
          <Image src={imageSrc} alt={imageAlt}></Image>
        </Link>
      </Box>
      <Box mb="2">
        <Input readOnly id="badge-text" type="text" value={badgeText} />
      </Box>

      <Tippy content="Copied!" visible={visible} onClickOutside={hide}>
        <Button
          sx={{
            bg: theme === "footer" ? "primary" : "primary",
            width: "full",
            cursor: "pointer",
          }}
          id="copy-badge-text"
          data-clipboard-target="#badge-text"
        >
          Copy badge Markdown
        </Button>
      </Tippy>
    </Box>
  );
};
export default Badge;
